function getLocaleFromCookie<
  AppLocales extends Locales,
  AppLocalePrefixMode extends LocalePrefixMode,
  AppPathnames extends Pathnames<AppLocales> | undefined,
  AppDomains extends DomainsConfig<AppLocales> | undefined
>(
  routing: Pick<
    ResolvedRoutingConfig<
      AppLocales,
      AppLocalePrefixMode,
      AppPathnames,
      AppDomains
    >,
    'localeCookie' | 'locales'
  >,
  requestCookies: RequestCookies
) {
  if (routing.localeCookie && requestCookies.has(routing.localeCookie.name)) {
    const value = requestCookies.get(routing.localeCookie.name)?.value;
    if (value && routing.locales.includes(value)) {
      return value;
    }
  }
}

async create(options: InternalOptions<"oauth">, origin?: string) {
  const { provider } = options
  if (!provider.checks.includes("state")) {
    if (origin) {
      throw new InvalidCheck(
        "State data was provided but the provider is not configured to use state"
      )
    }
    return
  }

  // IDEA: Allow the user to pass data to be stored in the state
  const payload = {
    origin,
    random: o.generateRandomState(),
  } satisfies EncodedState
  const value = await encode({
    secret: options.jwt.secret,
    token: payload,
    salt: encodedStateSalt,
    maxAge: STATE_MAX_AGE,
  })
  const cookie = await sealCookie("state", value, options)

  return { cookie, value }
}

async use(
  options: InternalOptions<WebAuthnProviderType>,
  cookies: RequestInternal["cookies"],
  resCookies: Cookie[]
): Promise<WebAuthnChallengePayload> {
  const cookieValue = cookies?.[options.cookies.webauthnChallenge.name]

  const parsed = await parseCookie("webauthnChallenge", cookieValue, options)

  const payload = await decode<WebAuthnChallengePayload>({
    secret: options.jwt.secret,
    token: parsed,
    salt: webauthnChallengeSalt,
  })

  // Clear the WebAuthn challenge cookie after use
  clearCookie("webauthnChallenge", options, resCookies)

  if (!payload) throw new InvalidCheck("WebAuthn challenge was missing")

  return payload
}

export async function createCallbackUrl({
  options,
  paramValue,
  cookieValue,
}: CreateCallbackUrlParams) {
  const { url, callbacks } = options

  let callbackUrl = url.origin

  if (paramValue) {
    // If callbackUrl form field or query parameter is passed try to use it if allowed
    callbackUrl = await callbacks.redirect({
      url: paramValue,
      baseUrl: url.origin,
    })
  } else if (cookieValue) {
    // If no callbackUrl specified, try using the value from the cookie if allowed
    callbackUrl = await callbacks.redirect({
      url: cookieValue,
      baseUrl: url.origin,
    })
  }

  return {
    callbackUrl,
    // Save callback URL in a cookie so that it can be used for subsequent requests in signin/signout/callback flow
    callbackUrlCookie: callbackUrl !== cookieValue ? callbackUrl : undefined,
  }
}

export function resolvePendingElicitation(
  response: ElicitationResponse,
): boolean {
  console.log('[store] Attempting to resolve:', response.id);
  console.log(
    '[store] Current pending IDs:',
    Array.from(pendingElicitations.keys()),
  );

  const pending = pendingElicitations.get(response.id);

  if (!pending) {
    console.log('[store] Not found in map!');
    return false;
  }

  console.log('[store] Found! Resolving...');
  clearTimeout(pending.timeoutId);
  pending.resolve(response);
  pendingElicitations.delete(response.id);
  console.log(
    '[store] Resolved and removed. Remaining count:',
    pendingElicitations.size,
  );
  return true;
}

